import { Component } from "react";

class Logo extends Component {
    render(){
        const { redesSociales } = this.props
        return (
            <div>
                {redesSociales.map(x => {
                    <div key={x.nombre} className="redSocial">
                        <img alt={x.nombre} src={x.enlace} />
                        <h3>{x.nombre}</h3>
                    </div>
                })}
            </div>
        )
    }
}

export default Logo
